mapper.select:
select id, realm_id as realmId, username, nickname, avatar, email, mobile, status, last_login_time as lastLoginTime, create_time, update_time from account a
and realm_id = #{request.realmId}
and (username like concat('%', #{request.keyword}, '%') or mobile like concat('%', #{request.keyword}, '%') or email like concat('%', #{request.keyword}, '%') or nickname like concat('%', #{request.keyword}, '%') )
and username like concat('%', #{request.username}, '%')
and mobile = #{request.mobile}
and email = #{request.email}
and status = #{request.status}
order by create_time desc

select count(1)
from realm
where id = #{realmId}

select l.id, r.name as realmName, l.login_entry_code as loginEntryCode, l.provider_type as providerType, l.login_type as loginType, l.login_identifier as loginIdentifier, l.success = 1 as success, l.fail_reason as failReason, l.ip, l.user_agent as userAgent, l.device_id as deviceId, l.create_time from iam_login_log l left join realm r on r.id = l.realm_id
l.account_id = #{accountId}
and l.login_type = #{request.loginType}
and l.success = case when #{request.success} = true then 1 else 0 end
and l.login_entry_code = #{request.loginEntryCode}
order by l.create_time desc
